// 连接状态指示器
// 统一管理 API / SSE / WebSocket 三路连接状态，断开时 toast 警告

import { toastWarning, toastInfo } from "./toast";

export type ConnState = "online" | "reconnecting" | "offline";

interface ConnElements {
  dot: HTMLElement;
  text: HTMLElement;
}

let elements: ConnElements | null = null;
let apiState: ConnState = "offline";
let sseState: ConnState = "offline";
let wsState: ConnState = "offline";
let wsActiveJobId = ""; // 当前 WS 是否为主动连接

function resolveElements(): ConnElements | null {
  const dot = document.getElementById("connDot");
  const text = document.getElementById("serverStateText");
  if (!dot || !text) return null;
  elements = { dot, text };
  return elements;
}

/** 综合三路状态取最差值用于展示 */
function aggregate(): ConnState {
  if (apiState === "offline" && sseState === "offline" && wsState === "offline") return "offline";
  if (apiState === "reconnecting" || sseState === "reconnecting" || wsState === "reconnecting") return "reconnecting";
  return "online";
}

function render(): void {
  const els = elements ?? resolveElements();
  if (!els) return;
  const state = aggregate();
  const labels: Record<ConnState, string> = {
    online: "API 在线",
    reconnecting: "重连中",
    offline: "API 离线",
  };
  els.text.textContent = labels[state];
  els.dot.className = `conn-dot conn-${state}`;
}

type Channel = "api" | "sse" | "ws";

function setState(channel: Channel, state: ConnState): void {
  const prev = channel === "api" ? apiState : channel === "sse" ? sseState : wsState;
  if (channel === "api") apiState = state;
  else if (channel === "sse") sseState = state;
  else wsState = state;

  if (prev === state) return;

  // 状态退化时提示
  if (channel === "ws" && wsActiveJobId) {
    if (state === "offline") toastWarning("日志连接已断开，正在尝试重连");
    else if (state === "online" && prev === "reconnecting") toastInfo("日志连接已恢复");
  }
  if (channel === "sse") {
    if (state === "reconnecting") toastWarning("任务推送连接异常，正在重连");
    else if (state === "online" && prev === "reconnecting") toastInfo("任务推送已恢复");
  }

  render();
}

export const connection = {
  /** API 健康检查结果 */
  setApi(state: ConnState): void {
    setState("api", state);
  },
  /** SSE 任务列表推送状态 */
  setSse(state: ConnState): void {
    setState("sse", state);
  },
  /** WebSocket 日志流状态 */
  setWs(state: ConnState, hasActiveJob = true): void {
    wsActiveJobId = hasActiveJob ? "active" : "";
    setState("ws", state);
  },
  /** 初始化展示 */
  init(): void {
    resolveElements();
    render();
  },
};
