// 转换表单
// 文件选择（支持拖拽）、实时校验、配置复用、上传进度、提交后激活任务监控

import { parseErrorText } from "../core/api";
import { toastError, toastSuccess } from "../core/toast";
import { bindButton } from "../core/button";
import { requireElement } from "../core/dom";
import { loadConfig, saveConfig } from "../core/storage";
import type { Monitor } from "./monitor";
import type { JobsList } from "./jobs-list";

const MODEL_SUFFIXES = [".pt", ".onnx"];
const DATASET_SUFFIXES = [".zip"];
const IMGSZ_MIN = 32;
const IMGSZ_MAX = 4096;
const IMGSZ_STEP = 32;
const IMAGES_MIN = 1;
const IMAGES_MAX = 5000;
const CONFIG_KEY = "form_config";
const TARGET_SIZE_DEFAULTS: Record<string, [number, number]> = {
  maixcam2: [640, 480],
  maixcam: [320, 224],
};

interface FormConfig {
  target: string;
  yolo_version: string;
  images_num: number;
  imgsz_width: number;
  imgsz_height: number;
  fast: boolean;
}

export interface FormHandlers {
  monitor: Monitor;
  jobsList: JobsList;
}

export function initForm(handlers: FormHandlers): void {
  const { monitor, jobsList } = handlers;
  const form = requireElement<HTMLFormElement>("jobForm");
  const modelFile = requireElement<HTMLInputElement>("modelFile");
  const datasetFile = requireElement<HTMLInputElement>("datasetFile");
  const modelFileControl = requireElement("modelFileControl");
  const datasetFileControl = requireElement("datasetFileControl");
  const modelFileName = requireElement("modelFileName");
  const datasetFileName = requireElement("datasetFileName");
  const modelFileInfo = requireElement("modelFileInfo");
  const datasetFileInfo = requireElement("datasetFileInfo");
  const modelName = requireElement<HTMLInputElement>("modelName");
  const yoloVersionInput = requireElement<HTMLInputElement>("yoloVersionInput");
  const imagesNum = requireElement<HTMLInputElement>("imagesNum");
  const imgszWidth = requireElement<HTMLInputElement>("imgszWidth");
  const imgszHeight = requireElement<HTMLInputElement>("imgszHeight");
  const imagesNumError = requireElement("imagesNumError");
  const imgszWidthError = requireElement("imgszWidthError");
  const imgszHeightError = requireElement("imgszHeightError");
  const submitButton = requireElement<HTMLButtonElement>("submitButton");
  const uploadProgress = requireElement("uploadProgress");
  const uploadProgressBar = requireElement("uploadProgressBar");
  const uploadProgressText = requireElement("uploadProgressText");
  const targetInputs = Array.from(form.querySelectorAll<HTMLInputElement>('input[name="target"]'));

  const submitLoading = bindButton(submitButton);

  // 在任务运行期间禁用提交按钮：当监控面板发出 job:started / job:finished 事件时响应
  document.addEventListener("job:started", () => {
    submitButton.disabled = true;
    submitLoading.setTooltip("已有任务在运行，等待完成后可再次提交");
  });
  document.addEventListener("job:finished", () => {
    submitButton.disabled = false;
    submitLoading.setTooltip("");
  });

  // ---- 配置复用：加载持久化配置 ----
  const saved = loadConfig<FormConfig>(CONFIG_KEY, {
    target: "maixcam2",
    yolo_version: "yolo26",
    images_num: 100,
    imgsz_width: 640,
    imgsz_height: 480,
    fast: true,
  });
  yoloVersionInput.value = saved.yolo_version;
  yoloVersionInput.dispatchEvent(new Event("change", { bubbles: true }));
  const savedTarget = targetInputs.find((input) => input.value === saved.target) || targetInputs[0];
  if (savedTarget) savedTarget.checked = true;
  imagesNum.value = String(saved.images_num);
  imgszWidth.value = String(saved.imgsz_width);
  imgszHeight.value = String(saved.imgsz_height);
  const fastCheckbox = form.querySelector<HTMLInputElement>('input[name="fast"]');
  if (fastCheckbox) fastCheckbox.checked = saved.fast;

  // ---- 配置复用：变更时保存 ----
  function saveFormConfig(): void {
    saveConfig<FormConfig>(CONFIG_KEY, {
      target: getSelectedTarget(),
      yolo_version: yoloVersionInput.value,
      images_num: Number(imagesNum.value) || 0,
      imgsz_width: Number(imgszWidth.value) || 0,
      imgsz_height: Number(imgszHeight.value) || 0,
      fast: fastCheckbox?.checked ?? true,
    });
  }

  [imagesNum, imgszWidth, imgszHeight, fastCheckbox, ...targetInputs].forEach((el) => {
    el?.addEventListener("change", saveFormConfig);
  });
  // yolo 版本通过自定义事件通知
  yoloVersionInput.addEventListener("change", saveFormConfig);

  targetInputs.forEach((input) => {
    input.addEventListener("change", () => {
      if (!input.checked) return;
      const size = TARGET_SIZE_DEFAULTS[input.value];
      if (!size) return;
      imgszWidth.value = String(size[0]);
      imgszHeight.value = String(size[1]);
      validateImgsz(imgszWidth, imgszWidthError);
      validateImgsz(imgszHeight, imgszHeightError);
      saveFormConfig();
    });
  });

  // ---- 实时校验 ----
  function validateImgsz(input: HTMLInputElement, errorEl: HTMLElement): boolean {
    const raw = input.value.trim();
    if (!raw) {
      showFieldError(input, errorEl, "不能为空");
      return false;
    }
    const val = Number(raw);
    if (!Number.isFinite(val)) {
      showFieldError(input, errorEl, "必须是数字");
      return false;
    }
    if (val < IMGSZ_MIN || val > IMGSZ_MAX) {
      showFieldError(input, errorEl, `范围 ${IMGSZ_MIN}-${IMGSZ_MAX}`);
      return false;
    }
    if (val % IMGSZ_STEP !== 0) {
      showFieldError(input, errorEl, `必须是 ${IMGSZ_STEP} 的倍数`);
      return false;
    }
    clearFieldError(input, errorEl);
    return true;
  }

  function validateImagesNum(): boolean {
    const raw = imagesNum.value.trim();
    if (!raw) {
      showFieldError(imagesNum, imagesNumError, "不能为空");
      return false;
    }
    const val = Number(raw);
    if (!Number.isFinite(val) || !Number.isInteger(val)) {
      showFieldError(imagesNum, imagesNumError, "必须是整数");
      return false;
    }
    if (val < IMAGES_MIN || val > IMAGES_MAX) {
      showFieldError(imagesNum, imagesNumError, `范围 ${IMAGES_MIN}-${IMAGES_MAX}`);
      return false;
    }
    clearFieldError(imagesNum, imagesNumError);
    return true;
  }

  function showFieldError(input: HTMLInputElement, errorEl: HTMLElement, msg: string): void {
    errorEl.textContent = msg;
    errorEl.hidden = false;
    input.closest(".field")?.classList.add("has-error");
  }

  function clearFieldError(input: HTMLInputElement, errorEl: HTMLElement): void {
    errorEl.hidden = true;
    errorEl.textContent = "";
    input.closest(".field")?.classList.remove("has-error");
  }

  function validateAll(): boolean {
    const w = validateImgsz(imgszWidth, imgszWidthError);
    const h = validateImgsz(imgszHeight, imgszHeightError);
    const n = validateImagesNum();
    return w && h && n;
  }

  function getSelectedTarget(): string {
    return targetInputs.find((input) => input.checked)?.value || "maixcam2";
  }

  imgszWidth.addEventListener("input", () => validateImgsz(imgszWidth, imgszWidthError));
  imgszHeight.addEventListener("input", () => validateImgsz(imgszHeight, imgszHeightError));
  imagesNum.addEventListener("input", validateImagesNum);

  // ---- 拖拽上传 ----
  bindDragDrop(modelFileControl, modelFile, MODEL_SUFFIXES);
  bindDragDrop(datasetFileControl, datasetFile, DATASET_SUFFIXES);

  // ---- 文件选择 ----
  modelFile.addEventListener("change", () => {
    handleFileSelect(modelFile, modelFileName, modelFileInfo, MODEL_SUFFIXES, "支持 .pt / .onnx");
    if (modelFile.files?.length) {
      const name = modelFile.files[0].name.replace(/\.[^.]+$/, "");
      modelName.value = name.replace(/[^A-Za-z0-9_.-]+/g, "_");
      saveFormConfig();
    }
  });

  datasetFile.addEventListener("change", () => {
    handleFileSelect(datasetFile, datasetFileName, datasetFileInfo, DATASET_SUFFIXES, "上传 .zip 文件");
  });

  // ---- 提交 ----
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    if (!validateAll()) {
      toastError("请修正表单中的错误后再提交");
      return;
    }
    submitLoading.start("上传中");
    resetProgress();

    try {
      const data = await uploadJob(new FormData(form));
      setProgress(100, "上传完成，转换任务已创建");
      hideProgressSoon();
      monitor.setActiveJob(data.job_id);
      await jobsList.refresh();
      toastSuccess("转换任务已创建");
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      toastError(`上传失败：${msg}`);
    } finally {
      submitLoading.stop();
    }
  });

  function uploadJob(body: FormData): Promise<{ job_id: string; status: string; job: string }> {
    return new Promise((resolve, reject) => {
      const xhr = new XMLHttpRequest();
      xhr.open("POST", "/api/jobs");

      xhr.upload.addEventListener("progress", (event) => {
        if (!event.lengthComputable) {
          uploadProgressText.textContent = "正在上传";
          return;
        }
        const percent = Math.max(1, Math.round((event.loaded / event.total) * 100));
        setProgress(percent, `正在上传 ${percent}%`);
        submitLoading.start(`上传中 ${percent}%`);
      });

      xhr.addEventListener("load", () => {
        if (xhr.status < 200 || xhr.status >= 300) {
          reject(new Error(parseErrorText(xhr.responseText, `HTTP ${xhr.status}`)));
          return;
        }
        try {
          resolve(JSON.parse(xhr.responseText));
        } catch (err) {
          reject(err instanceof Error ? err : new Error(String(err)));
        }
      });

      xhr.addEventListener("error", () => reject(new Error("上传失败")));
      xhr.send(body);
    });
  }

  // ---- 辅助函数 ----
  function handleFileSelect(
    input: HTMLInputElement,
    nameEl: HTMLElement,
    infoEl: HTMLElement,
    allowedSuffixes: string[],
    fallback: string,
  ): void {
    if (!input.files?.length) {
      nameEl.textContent = fallback;
      infoEl.hidden = true;
      return;
    }
    const file = input.files[0];
    nameEl.textContent = file.name;
    renderFileInfo(infoEl, file, allowedSuffixes);
  }

  function resetProgress(): void {
    uploadProgress.classList.add("active");
    uploadProgressText.classList.add("active");
    setProgress(0, "等待上传");
  }

  function setProgress(percent: number, text: string): void {
    uploadProgressBar.style.width = `${percent}%`;
    uploadProgressText.textContent = text;
  }

  function hideProgressSoon(): void {
    setTimeout(() => {
      uploadProgress.classList.remove("active");
      uploadProgressText.classList.remove("active");
      uploadProgressBar.style.width = "0";
      uploadProgressText.textContent = "等待上传";
    }, 900);
  }

  // 初始校验一次（不显示错误，仅同步状态）
  validateImgsz(imgszWidth, imgszWidthError);
  validateImgsz(imgszHeight, imgszHeightError);
  validateImagesNum();
}

/** 绑定拖拽上传到文件控件 */
function bindDragDrop(control: HTMLElement, input: HTMLInputElement, allowedSuffixes: string[]): void {
  const hintEl = control.querySelector<HTMLElement>("em");
  const defaultText = hintEl?.textContent || "拖拽上传文件";
  const dragText = control.dataset.dragText || "松开上传文件";

  control.addEventListener("dragover", (event) => {
    event.preventDefault();
    control.classList.add("drag-over");
    if (hintEl) hintEl.textContent = dragText;
  });

  control.addEventListener("dragleave", () => {
    control.classList.remove("drag-over");
    if (hintEl) hintEl.textContent = defaultText;
  });

  control.addEventListener("drop", (event) => {
    event.preventDefault();
    control.classList.remove("drag-over");
    if (hintEl) hintEl.textContent = defaultText;
    const files = event.dataTransfer?.files;
    if (!files?.length) return;
    const file = files[0];
    const suffix = "." + (file.name.split(".").pop() || "").toLowerCase();
    if (!allowedSuffixes.includes(suffix)) {
      toastError(`不支持的文件类型 ${suffix}，仅支持 ${allowedSuffixes.join(" / ")}`);
      return;
    }
    // 通过 DataTransfer 将拖入文件赋值给 input
    const dt = new DataTransfer();
    dt.items.add(file);
    input.files = dt.files;
    input.dispatchEvent(new Event("change", { bubbles: true }));
  });
}

/** 渲染文件信息（名称 + 大小） */
function renderFileInfo(el: HTMLElement, file: File, allowedSuffixes: string[]): void {
  const suffix = "." + (file.name.split(".").pop() || "").toLowerCase();
  const isValid = allowedSuffixes.includes(suffix);
  el.innerHTML = "";
  const nameSpan = document.createElement("span");
  nameSpan.className = "file-info-name";
  nameSpan.textContent = file.name;
  const sizeBadge = document.createElement("span");
  sizeBadge.className = "file-info-size" + (isValid ? "" : " invalid");
  sizeBadge.textContent = formatFileSize(file.size);
  el.appendChild(nameSpan);
  el.appendChild(sizeBadge);
  el.hidden = false;
}

function formatFileSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  if (bytes < 1024 * 1024 * 1024) return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  return `${(bytes / (1024 * 1024 * 1024)).toFixed(2)} GB`;
}
