// Toast 通知系统
// 右上角堆叠展示，支持 success/error/warning/info，自动消失+手动关闭

export type ToastKind = "success" | "error" | "warning" | "info";

export interface ToastOptions {
  /** 自动消失时长，毫秒；0 表示不自动消失 */
  duration?: number;
  /** 是否可手动关闭，默认 true */
  dismissible?: boolean;
}

const DEFAULT_DURATION = 4000;
const ICONS: Record<ToastKind, string> = {
  success: "✓",
  error: "✕",
  warning: "!",
  info: "i",
};

let container: HTMLElement | null = null;

function ensureContainer(): HTMLElement {
  if (container && document.body.contains(container)) return container;
  container = document.getElementById("toastContainer");
  if (!container) {
    container = document.createElement("div");
    container.id = "toastContainer";
    container.className = "toast-container";
    container.setAttribute("aria-live", "polite");
    container.setAttribute("aria-atomic", "false");
    document.body.appendChild(container);
  }
  return container;
}

export function toast(message: string, kind: ToastKind = "info", options: ToastOptions = {}): () => void {
  const { duration = DEFAULT_DURATION, dismissible = true } = options;
  const root = ensureContainer();

  const el = document.createElement("div");
  el.className = `toast toast-${kind}`;
  el.setAttribute("role", kind === "error" ? "alert" : "status");

  const icon = document.createElement("span");
  icon.className = "toast-icon";
  icon.textContent = ICONS[kind];

  const body = document.createElement("div");
  body.className = "toast-body";
  body.textContent = message;

  el.append(icon, body);

  let timer: number | undefined;

  const close = (): void => {
    if (timer !== undefined) window.clearTimeout(timer);
    el.classList.add("toast-leaving");
    el.addEventListener("transitionend", () => el.remove(), { once: true });
  };

  if (dismissible) {
    const btn = document.createElement("button");
    btn.className = "toast-close";
    btn.type = "button";
    btn.setAttribute("aria-label", "关闭通知");
    btn.textContent = "×";
    btn.addEventListener("click", close);
    el.appendChild(btn);
  }

  root.appendChild(el);
  // 触发进入动画
  requestAnimationFrame(() => el.classList.add("toast-visible"));

  if (duration > 0) {
    timer = window.setTimeout(close, duration);
  }

  return close;
}

export function toastSuccess(message: string, options?: ToastOptions): () => void {
  return toast(message, "success", options);
}

export function toastError(message: string, options?: ToastOptions): () => void {
  return toast(message, "error", { duration: 0, ...options });
}

export function toastWarning(message: string, options?: ToastOptions): () => void {
  return toast(message, "warning", options);
}

export function toastInfo(message: string, options?: ToastOptions): () => void {
  return toast(message, "info", options);
}
