// 应用入口：初始化各模块并串联回调

import { api } from "./core/api";
import { connection } from "./core/connection";
import { requireElement } from "./core/dom";
import { initTheme } from "./core/theme";
import { initYoloSelect } from "./ui/yolo-select";
import { initMonitor } from "./ui/monitor";
import { initJobsList } from "./ui/jobs-list";
import { initForm } from "./ui/form";
import "./styles.css";

async function checkHealth(): Promise<void> {
  try {
    await api.health();
    connection.setApi("online");
  } catch {
    connection.setApi("offline");
  }
}

/** 环境检测：本地开发时显示 DEV 标识 */
function detectEnv(): void {
  const badge = document.getElementById("envBadge");
  if (!badge) return;
  const host = window.location.hostname;
  if (host === "localhost" || host === "127.0.0.1" || host === "0.0.0.0") {
    badge.hidden = false;
    badge.textContent = "DEV";
  }
}

function main(): void {
  initTheme();
  detectEnv();
  connection.init();
  initYoloSelect();

  const monitor = initMonitor();
  const jobsList = initJobsList();

  // 任务列表"查看" → 激活监控面板
  jobsList.onViewJob = (id: string) => {
    monitor.setActiveJob(id);
  };

  // 任务列表删除后，若删除的是当前监控任务则清空面板
  let activeJobId = "";
  const originalSetActive = monitor.setActiveJob.bind(monitor);
  // 包装 setActiveJob 记录当前 id
  // 通过 refresh 按钮也能触发刷新
  jobsList.onDeleted = (id: string) => {
    if (id === activeJobId) {
      monitor.clearActive();
      activeJobId = "";
    }
  };

  // 拦截 setActiveJob 以记录 activeJobId
  const wrappedMonitor = {
    ...monitor,
    setActiveJob(id: string) {
      activeJobId = id;
      originalSetActive(id);
    },
  };

  initForm({ monitor: wrappedMonitor, jobsList });

  // 刷新按钮
  const refreshButton = requireElement<HTMLButtonElement>("refreshButton");
  refreshButton.addEventListener("click", () => {
    monitor.refreshJob();
  });

  checkHealth();
  // 定期健康检查（每 30 秒）
  setInterval(checkHealth, 30000);
}

main();
