// 任务监控面板
// 管理当前任务详情渲染、WebSocket 日志流、阶段进度、取消任务、日志着色与工具栏

import type { Job, JobStatus, StreamMessage } from "../types";
import { api } from "../core/api";
import { connection } from "../core/connection";
import { confirmDialog } from "../core/modal";
import { toastSuccess, toastInfo } from "../core/toast";
import { requireElement } from "../core/dom";

const LOG_MAX = 160000;
const LOG_DISPLAY_MAX = 180000;

type StepState = "pending" | "active" | "done" | "skipped";

/** 后端 stage 值到进度步骤的映射 */
const STAGE_PROGRESS: Record<string, { done: number; active: number }> = {
  prepare_done: { done: 1, active: 1 },
  exporting: { done: 1, active: 1 },
  export_done: { done: 2, active: 2 },
  prebuilding: { done: 2, active: 2 },
  prebuild_done: { done: 3, active: 3 },
  pulsar2: { done: 3, active: 3 },
  pulsar2_done: { done: 4, active: 4 },
  tpumlir: { done: 3, active: 3 },
  tpumlir_done: { done: 4, active: 4 },
  packaging: { done: 4, active: 4 },
  done: { done: 5, active: 5 },
};

export interface Monitor {
  setActiveJob(id: string): void;
  refreshJob(): Promise<void>;
  clearActive(): void;
}

export function initMonitor(): Monitor {
  const jobStatus = requireElement("jobStatus");
  const jobId = requireElement("jobId");
  const jobModel = requireElement("jobModel");
  const jobDone = requireElement("jobDone");
  const jobYolo = requireElement("jobYolo");
  const jobTarget = requireElement("jobTarget");
  const jobSize = requireElement("jobSize");
  const jobImages = requireElement("jobImages");
  const jobMode = requireElement("jobMode");
  const jobElapsed = requireElement("jobElapsed");
  const jobError = requireElement("jobError");
  const logView = requireElement("logView");
  const downloadButton = requireElement<HTMLAnchorElement>("downloadButton");
  const stageProgress = requireElement("stageProgress");
  const cancelJobButton = requireElement<HTMLButtonElement>("cancelJobButton");
  const logToolbar = requireElement("logToolbar");
  const logCopyBtn = requireElement<HTMLButtonElement>("logCopyBtn");
  const logDownloadBtn = requireElement<HTMLButtonElement>("logDownloadBtn");
  const logClearBtn = requireElement<HTMLButtonElement>("logClearBtn");
  const logAutoScroll = requireElement<HTMLInputElement>("logAutoScroll");
  const logTruncation = requireElement("logTruncation");
  const conversionStageLabel = requireElement("conversionStageLabel");

  let activeJobId = "";
  let lastJobStatus = "";
  let streamSocket: WebSocket | null = null;
  let currentLog = "";
  let elapsedTimer: number | undefined;
  let jobCreatedAt: string = "";
  let jobCompletedAt: string = "";

  // ---- 日志工具栏 ----
  logCopyBtn.addEventListener("click", async () => {
    try {
      await navigator.clipboard.writeText(currentLog);
      toastSuccess("日志已复制到剪贴板");
    } catch {
      toastInfo("复制失败，请手动选择文本复制");
    }
  });

  logDownloadBtn.addEventListener("click", () => {
    const blob = new Blob([currentLog], { type: "text/plain;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${activeJobId || "job"}.log`;
    a.click();
    URL.revokeObjectURL(url);
  });

  logClearBtn.addEventListener("click", () => {
    currentLog = "";
    logTruncation.hidden = true;
    logView.innerHTML = '<span class="log-placeholder">日志已清空，等待新输出...</span>';
  });

  // ---- 取消任务 ----
  cancelJobButton.addEventListener("click", async () => {
    if (!activeJobId) return;
    const confirmed = await confirmDialog(`确定取消任务 ${activeJobId}？\n正在运行的转换进程会被终止。`, {
      title: "取消任务",
      confirmText: "取消任务",
      danger: true,
    });
    if (!confirmed) return;
    try {
      await api.cancelJob(activeJobId);
      toastSuccess("任务已取消");
    } catch {
      // api 层已 toast 错误
    }
  });

  function setStatus(status: JobStatus | string): void {
    jobStatus.textContent = statusText(status);
    jobStatus.className = `status-badge ${status || "idle"}`;
  }

  /** 渲染带着色的日志行 */
  function appendLog(text: string): void {
    if (!text) return;
    currentLog += text;
    if (currentLog.length > LOG_DISPLAY_MAX) {
      currentLog = currentLog.slice(currentLog.length - LOG_MAX);
      logTruncation.hidden = false;
    }

    // 按行着色渲染
    logView.innerHTML = "";
    const lines = currentLog.split("\n");
    const frag = document.createDocumentFragment();
    for (const line of lines) {
      const span = document.createElement("span");
      span.className = classifyLogLine(line);
      span.textContent = line + "\n";
      frag.appendChild(span);
    }
    logView.appendChild(frag);

    if (logAutoScroll.checked) {
      logView.scrollTop = logView.scrollHeight;
    }
  }

  function renderJob(job: Job): void {
    setStatus(job.status || "unknown");
    jobId.textContent = job.job_id || activeJobId || "-";
    jobModel.textContent = [job.model_name, job.yolo_version].filter(Boolean).join(" / ") || "-";
    jobDone.textContent = job.completed_at || "-";
    jobYolo.textContent = [job.yolo_version, job.task].filter(Boolean).join(" / ") || "-";
    jobTarget.textContent = formatTarget(job.target);
    jobSize.textContent = formatImageSize(job.imgsz);
    jobImages.textContent = formatLabelsAndImages(job);
    jobMode.textContent = job.fast ? "快速" : "完整";
    jobCreatedAt = job.created_at || jobCreatedAt;
    jobCompletedAt = job.completed_at || "";
    renderJobError(job);
    renderStageProgress(job);
    renderElapsed(job);
    updateCancelButton(job);
    logToolbar.hidden = !activeJobId;

    // 派发全局事件，通知外部当前任务状态变化（方便表单等模块响应）
    const status = job.status || "unknown";
    const isFinished = status === "success" || status === "failed" || status === "cancelled";
    if (isFinished && lastJobStatus !== "finished") {
      document.dispatchEvent(new CustomEvent("job:finished", { detail: { id: job.job_id || activeJobId, status } }));
      lastJobStatus = "finished";
    } else if (!isFinished) {
      lastJobStatus = status;
    }

    if (job.status === "success") {
      downloadButton.href = `/api/jobs/${job.job_id || activeJobId}/download`;
      downloadButton.classList.remove("disabled");
      downloadButton.classList.add("ready");
      downloadButton.removeAttribute("aria-disabled");
    } else {
      downloadButton.classList.remove("ready");
    }
  }

  function renderJobError(job: Job): void {
    let message = "";
    if (job.status === "failed") message = job.error || "转换失败，请查看日志。";
    else if (job.status === "cancelled") message = "任务已取消。";
    jobError.textContent = message;
    jobError.hidden = !message;
  }

  /** 渲染 5 阶段进度条 */
  function renderStageProgress(job: Job): void {
    const status = job.status || "unknown";
    const isOnnxInput = (job.input_suffix || (job.input_model || "").split(".").pop() || "").toLowerCase() === "onnx";

    // 任务未开始或 idle 时不显示进度条
    if (status === "idle" || (!job.stage && status === "queued")) {
      stageProgress.hidden = true;
      return;
    }
    stageProgress.hidden = false;

    const progress = STAGE_PROGRESS[job.stage || ""];
    const doneCount = progress?.done ?? 0;
    const activeCount = progress?.active ?? 0;
    const isFinished = status === "success" || status === "failed" || status === "cancelled";
    const isCancelled = status === "cancelled";
    conversionStageLabel.textContent = job.target === "maixcam" ? "TPU-MLIR 转换" : "Pulsar2 转换";

    const steps = stageProgress.querySelectorAll<HTMLElement>(".stage-step");
    steps.forEach((step, index) => {
      step.classList.remove("stage-pending", "stage-active", "stage-done", "stage-skipped");
      let state: StepState;
      if (isCancelled) {
        state = index < doneCount ? "done" : "pending";
      } else if (status === "success") {
        state = "done";
      } else if (index === 1 && isOnnxInput) {
        // .onnx 输入跳过导出步骤
        state = doneCount >= 1 ? "skipped" : "pending";
      } else if (index < doneCount) {
        state = "done";
      } else if (index === activeCount && !isFinished) {
        state = "active";
      } else {
        state = "pending";
      }
      step.classList.add(`stage-${state}`);
    });
  }

  /** 渲染耗时 */
  function renderElapsed(job: Job): void {
    jobCreatedAt = job.created_at || jobCreatedAt;
    jobCompletedAt = job.completed_at || "";
    if (!jobCreatedAt) {
      jobElapsed.textContent = "-";
      return;
    }
    const start = new Date(jobCreatedAt).getTime();
    if (isNaN(start)) {
      jobElapsed.textContent = "-";
      return;
    }
    const end = jobCompletedAt ? new Date(jobCompletedAt).getTime() : Date.now();
    if (isNaN(end)) {
      jobElapsed.textContent = "-";
      return;
    }
    jobElapsed.textContent = formatDuration(end - start);
  }

  /** 更新取消按钮可见性 */
  function updateCancelButton(job: Job): void {
    const status = job.status || "unknown";
    cancelJobButton.hidden = status !== "queued" && status !== "running";
  }

  function openLogStream(id: string): void {
    if (streamSocket) {
      streamSocket.close();
      streamSocket = null;
    }

    const protocol = window.location.protocol === "https:" ? "wss" : "ws";
    streamSocket = new WebSocket(`${protocol}://${window.location.host}/api/jobs/${id}/stream`);

    streamSocket.addEventListener("open", () => {
      connection.setWs("online");
      appendLog("日志连接已建立\n");
    });

    streamSocket.addEventListener("message", (event) => {
      let data: StreamMessage;
      try {
        data = JSON.parse(event.data);
      } catch {
        appendLog(`${event.data}\n`);
        return;
      }
      if (data.type === "job") {
        renderJob(data.job);
      } else if (data.type === "log") {
        appendLog(data.text);
      } else if (data.type === "error") {
        appendLog(`${data.message}\n`);
        setStatus("failed");
      }
    });

    streamSocket.addEventListener("close", () => {
      connection.setWs("offline", false);
      refreshJob();
    });

    streamSocket.addEventListener("error", () => {
      connection.setWs("reconnecting");
    });
  }

  function setActiveJob(id: string): void {
    activeJobId = id;
    currentLog = "";
    logTruncation.hidden = true;
    jobId.textContent = id;
    downloadButton.href = "#";
    downloadButton.classList.add("disabled");
    downloadButton.classList.remove("ready");
    downloadButton.setAttribute("aria-disabled", "true");
    logView.innerHTML = '<span class="log-placeholder">等待任务输出...</span>';
    logToolbar.hidden = false;
    startElapsedTimer();
    openLogStream(id);
    // 通知外部任务已开始
    lastJobStatus = "";
    document.dispatchEvent(new CustomEvent("job:started", { detail: { id } }));
  }

  async function refreshJob(): Promise<void> {
    if (!activeJobId) return;
    try {
      const job = await api.getJob(activeJobId);
      renderJob(job);
    } catch {
      // api 层已 toast
    }
  }

  function clearActive(): void {
    if (streamSocket) {
      streamSocket.close();
      streamSocket = null;
    }
    stopElapsedTimer();
    activeJobId = "";
    currentLog = "";
    jobId.textContent = "-";
    jobModel.textContent = "-";
    jobDone.textContent = "-";
    jobYolo.textContent = "-";
    jobTarget.textContent = "-";
    jobSize.textContent = "-";
    jobImages.textContent = "-";
    jobMode.textContent = "-";
    jobElapsed.textContent = "-";
    jobError.hidden = true;
    jobError.textContent = "";
    stageProgress.hidden = true;
    cancelJobButton.hidden = true;
    logToolbar.hidden = true;
    setStatus("idle");
    logView.innerHTML = '<span class="log-placeholder">任务已删除</span>';
    downloadButton.href = "#";
    downloadButton.classList.add("disabled");
    downloadButton.classList.remove("ready");
    downloadButton.setAttribute("aria-disabled", "true");
    connection.setWs("offline", false);
  }

  function startElapsedTimer(): void {
    stopElapsedTimer();
    elapsedTimer = window.setInterval(() => {
      if (activeJobId && !jobCompletedAt) {
        const start = new Date(jobCreatedAt).getTime();
        if (!isNaN(start)) {
          jobElapsed.textContent = formatDuration(Date.now() - start);
        }
      }
    }, 1000);
  }

  function stopElapsedTimer(): void {
    if (elapsedTimer !== undefined) {
      window.clearInterval(elapsedTimer);
      elapsedTimer = undefined;
    }
  }

  return {
    setActiveJob,
    refreshJob,
    clearActive,
  };
}

/** 日志行分类着色 */
function classifyLogLine(line: string): string {
  const upper = line.toUpperCase();
  if (upper.includes("TRACEBACK") || upper.includes("ERROR") || upper.includes("FAILED") || upper.includes("EXCEPTION")) {
    return "log-line-error";
  }
  if (upper.includes("WARN")) {
    return "log-line-warn";
  }
  if (/^Step\s+\d+/.test(line.trim())) {
    return "log-line-step";
  }
  if (upper.includes("DONE") || upper.includes("SAVED:") || upper.includes("SUCCESS")) {
    return "log-line-success";
  }
  return "log-line-normal";
}

function formatImageSize(size: unknown): string {
  if (!Array.isArray(size) || size.length < 2) return "-";
  return `${size[0]} x ${size[1]}`;
}

function formatLabelsAndImages(job: Job): string {
  const labels = Number.isFinite(Number(job.labels_num)) ? `${job.labels_num}` : "-";
  const images = Number.isFinite(Number(job.images_num)) ? `${job.images_num}` : "-";
  return `${labels} / ${images}`;
}

function formatTarget(target?: string): string {
  const names: Record<string, string> = {
    maixcam2: "MaixCam2",
    maixcam: "MaixCAM / Pro",
  };
  return target ? names[target] || target : "-";
}

function formatDuration(ms: number): string {
  if (ms < 0) return "-";
  const totalSec = Math.floor(ms / 1000);
  const h = Math.floor(totalSec / 3600);
  const m = Math.floor((totalSec % 3600) / 60);
  const s = totalSec % 60;
  if (h > 0) return `${h}h ${m}m ${s}s`;
  if (m > 0) return `${m}m ${s}s`;
  return `${s}s`;
}

const STATUS_TEXTS: Record<string, string> = {
  queued: "排队中",
  running: "转换中",
  success: "已完成",
  failed: "失败",
  cancelled: "已取消",
  unknown: "未知",
  idle: "未开始",
};

export function statusText(status: JobStatus | string): string {
  return STATUS_TEXTS[status] || status || "未开始";
}
