// 最近任务列表
// SSE 实时推送 + 状态筛选 + 删除确认（自定义 Modal）

import type { JobSummary } from "../types";
import { api } from "../core/api";
import { connection } from "../core/connection";
import { toastSuccess } from "../core/toast";
import { confirmDialog } from "../core/modal";
import { requireElement } from "../core/dom";
import { statusText } from "./monitor";

const PAGE_SIZE = 20;

export interface JobsList {
  refresh(): Promise<void>;
  onViewJob: (id: string) => void;
  onDeleted: (id: string) => void;
}

export function initJobsList(): JobsList {
  const list = requireElement("jobsList");
  const reloadBtn = requireElement<HTMLButtonElement>("reloadJobs");
  const jobsFilter = requireElement("jobsFilter");
  const jobsCount = requireElement("jobsCount");

  let jobsSource: EventSource | null = null;
  let viewCallback: (id: string) => void = () => {};
  let deletedCallback: (id: string) => void = () => {};
  let allJobs: JobSummary[] = [];
  let activeFilter: string = "all";
  let visibleCount = PAGE_SIZE;

  reloadBtn.addEventListener("click", () => refresh());

  // ---- 筛选按钮 ----
  jobsFilter.addEventListener("click", (event) => {
    const btn = (event.target as HTMLElement).closest<HTMLElement>(".filter-btn");
    if (!btn) return;
    const filter = btn.dataset.filter || "all";
    if (filter === activeFilter) return;
    activeFilter = filter;
    visibleCount = PAGE_SIZE;
    jobsFilter.querySelectorAll(".filter-btn").forEach((b) => b.classList.toggle("active", b === btn));
    render();
  });

  function getFilteredJobs(): JobSummary[] {
    if (activeFilter === "all") return allJobs;
    if (activeFilter === "running") {
      return allJobs.filter((j) => j.status === "queued" || j.status === "running");
    }
    return allJobs.filter((j) => j.status === activeFilter);
  }

  function render(): void {
    list.innerHTML = "";
    const filtered = getFilteredJobs();

    // 更新计数
    if (activeFilter === "all") {
      jobsCount.textContent = `共 ${allJobs.length} 个任务`;
    } else {
      jobsCount.textContent = `${filtered.length} / ${allJobs.length} 个任务`;
    }

    if (!allJobs.length) {
      renderEmpty("暂无任务", "上传模型和数据集开始第一次转换");
      return;
    }

    if (!filtered.length) {
      renderEmpty("没有匹配的任务", `当前筛选下无任务，试试切换到"全部"`);
      return;
    }

    const visible = filtered.slice(0, visibleCount);
    for (const job of visible) {
      list.appendChild(createJobRow(job));
    }

    // 加载更多
    if (filtered.length > visible.length) {
      const more = document.createElement("button");
      more.className = "secondary-button load-more-btn";
      more.type = "button";
      more.textContent = `加载更多（剩余 ${filtered.length - visible.length} 个）`;
      more.addEventListener("click", () => {
        visibleCount += PAGE_SIZE;
        render();
      });
      list.appendChild(more);
    }
  }

  function createJobRow(job: JobSummary): HTMLElement {
    const row = document.createElement("div");
    row.className = "job-row";

    const idCol = document.createElement("div");
    idCol.className = "job-id";
    idCol.textContent = job.job_id;
    idCol.title = job.job_id;

    const status = document.createElement("div");
    status.className = `status-badge ${job.status || "unknown"}`;
    status.textContent = statusText(job.status);

    const model = document.createElement("div");
    model.className = "job-model";
    const modelName = job.model_name || "-";
    const yoloVer = job.yolo_version || "";
    model.innerHTML = yoloVer
      ? `${escapeHtml(modelName)} <em>${escapeHtml(yoloVer)}</em>`
      : escapeHtml(modelName);
    model.title = [modelName, formatTarget(job.target), yoloVer].filter(Boolean).join(" · ");

    const labels = document.createElement("div");
    labels.className = "muted";
    labels.style.fontSize = "12px";
    labels.textContent = job.labels_num != null ? `${job.labels_num} 类` : "-";

    const time = document.createElement("div");
    time.className = "muted job-time";
    time.style.fontSize = "12px";
    time.textContent = [formatTarget(job.target), job.completed_at || job.created_at || "-"].filter(Boolean).join(" / ");

    const viewBtn = document.createElement("button");
    viewBtn.className = "secondary-button";
    viewBtn.type = "button";
    viewBtn.textContent = "查看";
    viewBtn.addEventListener("click", () => viewCallback(job.job_id));

    const deleteBtn = document.createElement("button");
    deleteBtn.className = "danger-button";
    deleteBtn.type = "button";
    deleteBtn.textContent = "删除";
    const isActive = job.status === "queued" || job.status === "running";
    deleteBtn.disabled = isActive;
    deleteBtn.title = isActive ? "运行中任务不可删除" : "";
    deleteBtn.addEventListener("click", () => deleteJob(job.job_id));

    const actions = document.createElement("div");
    actions.className = "row-actions";
    actions.append(viewBtn, deleteBtn);

    row.append(idCol, status, model, labels, time, actions);
    return row;
  }

  function renderEmpty(title: string, hint: string): void {
    const empty = document.createElement("div");
    empty.className = "jobs-empty";
    empty.innerHTML = `<span class="jobs-empty-icon">📋</span><span>${escapeHtml(title)}</span><span class="jobs-empty-hint">${escapeHtml(hint)}</span>`;
    list.appendChild(empty);
  }

  async function refresh(): Promise<void> {
    try {
      const data = await api.listJobs();
      allJobs = data.jobs || [];
      render();
    } catch {
      // api 层已 toast 错误
    }
  }

  async function deleteJob(id: string): Promise<void> {
    const confirmed = await confirmDialog(`删除任务 ${id}？\n任务目录和转换结果都会被删除。`, {
      title: "删除任务",
      confirmText: "删除",
      danger: true,
    });
    if (!confirmed) return;

    try {
      await api.deleteJob(id);
      toastSuccess(`任务 ${id} 已删除`);
      deletedCallback(id);
      await refresh();
    } catch {
      // api 层已 toast 错误
    }
  }

  function openEvents(): void {
    if (!window.EventSource) {
      refresh();
      return;
    }
    if (jobsSource) jobsSource.close();

    jobsSource = new EventSource("/api/jobs/events");
    jobsSource.addEventListener("jobs", (event) => {
      try {
        const data = JSON.parse(event.data) as { jobs: JobSummary[] };
        allJobs = data.jobs || [];
        render();
      } catch (err) {
        console.error("failed to parse jobs event", err);
      }
    });
    jobsSource.addEventListener("open", () => {
      connection.setSse("online");
    });
    jobsSource.addEventListener("error", () => {
      connection.setSse("reconnecting");
    });
  }

  openEvents();

  return {
    refresh,
    get onViewJob() {
      return viewCallback;
    },
    set onViewJob(fn: (id: string) => void) {
      viewCallback = fn;
    },
    get onDeleted() {
      return deletedCallback;
    },
    set onDeleted(fn: (id: string) => void) {
      deletedCallback = fn;
    },
  };
}

function escapeHtml(text: string): string {
  const div = document.createElement("div");
  div.textContent = text;
  return div.innerHTML;
}

function formatTarget(target?: string): string {
  const names: Record<string, string> = {
    maixcam2: "MaixCam2",
    maixcam: "MaixCAM / Pro",
  };
  return target ? names[target] || target : "";
}
