// 自定义 Modal 组件
// 替换原生 window.confirm / window.alert，支持确认/危险操作样式

export interface ModalOptions {
  title?: string;
  message: string;
  /** 确认按钮文字，默认"确认" */
  confirmText?: string;
  /** 取消按钮文字，默认"取消" */
  cancelText?: string;
  /** 危险操作样式（红色确认按钮） */
  danger?: boolean;
  /** 是否仅显示确认（无取消），默认 false */
  confirmOnly?: boolean;
}

export interface ModalResult {
  confirmed: boolean;
}

let root: HTMLElement | null = null;

function ensureRoot(): HTMLElement {
  if (root && document.body.contains(root)) return root;
  root = document.getElementById("modalRoot");
  if (!root) {
    root = document.createElement("div");
    root.id = "modalRoot";
    root.className = "modal-root";
    root.setAttribute("aria-hidden", "true");
    document.body.appendChild(root);
  }
  return root;
}

export function showModal(options: ModalOptions): Promise<ModalResult> {
  const {
    title = "",
    message,
    confirmText = "确认",
    cancelText = "取消",
    danger = false,
    confirmOnly = false,
  } = options;

  const root = ensureRoot();
  root.innerHTML = "";

  const overlay = document.createElement("div");
  overlay.className = "modal-overlay";

  const dialog = document.createElement("div");
  dialog.className = "modal-dialog";
  if (danger) dialog.classList.add("modal-danger");
  dialog.setAttribute("role", "alertdialog");
  dialog.setAttribute("aria-modal", "true");

  if (title) {
    const head = document.createElement("div");
    head.className = "modal-title";
    head.textContent = title;
    dialog.appendChild(head);
  }

  const body = document.createElement("div");
  body.className = "modal-message";
  body.textContent = message;
  dialog.appendChild(body);

  const footer = document.createElement("div");
  footer.className = "modal-footer";

  return new Promise((resolve) => {
    let resolved = false;
    const finish = (confirmed: boolean): void => {
      if (resolved) return;
      resolved = true;
      overlay.classList.add("modal-leaving");
      overlay.addEventListener("transitionend", () => {
        root.innerHTML = "";
        root.setAttribute("aria-hidden", "true");
        document.removeEventListener("keydown", onKey);
        resolve({ confirmed });
      }, { once: true });
    };

    const onKey = (e: KeyboardEvent): void => {
      if (e.key === "Escape" && !confirmOnly) {
        e.preventDefault();
        finish(false);
      } else if (e.key === "Enter") {
        e.preventDefault();
        finish(true);
      }
    };

    if (!confirmOnly) {
      const cancelBtn = document.createElement("button");
      cancelBtn.type = "button";
      cancelBtn.className = "secondary-button modal-cancel";
      cancelBtn.textContent = cancelText;
      cancelBtn.addEventListener("click", () => finish(false));
      footer.appendChild(cancelBtn);
    }

    const confirmBtn = document.createElement("button");
    confirmBtn.type = "button";
    confirmBtn.className = danger ? "danger-button modal-confirm" : "primary-button modal-confirm";
    confirmBtn.textContent = confirmText;
    confirmBtn.addEventListener("click", () => finish(true));
    footer.appendChild(confirmBtn);

    dialog.appendChild(footer);
    overlay.appendChild(dialog);
    root.appendChild(overlay);
    root.setAttribute("aria-hidden", "false");

    overlay.addEventListener("click", (e) => {
      if (e.target === overlay && !confirmOnly) finish(false);
    });

    document.addEventListener("keydown", onKey);
    // 聚焦确认按钮以便键盘操作
    requestAnimationFrame(() => confirmBtn.focus());
  });
}

/** 简易确认弹窗，返回 true 表示用户确认 */
export async function confirmDialog(message: string, options?: Omit<ModalOptions, "message" | "confirmOnly">): Promise<boolean> {
  const result = await showModal({ message, confirmOnly: false, ...options });
  return result.confirmed;
}

/** 简易提示弹窗（仅确认按钮） */
export async function alertDialog(message: string, options?: Omit<ModalOptions, "message" | "confirmOnly">): Promise<void> {
  await showModal({ message, confirmOnly: true, ...options });
}
