// YOLO 版本下拉选择器
// 支持键盘导航：ArrowUp/Down/Home/End/Enter/Escape

import { requireElement } from "../core/dom";

export function initYoloSelect(): { getValue: () => string } {
  const select = requireElement("yoloSelect");
  const button = requireElement<HTMLButtonElement>("yoloSelectButton");
  const menu = requireElement("yoloSelectMenu");
  const input = requireElement<HTMLInputElement>("yoloVersionInput");
  const labelEl = requireElement("yoloSelectLabel");
  const metaEl = requireElement("yoloSelectMeta");

  const options = Array.from(menu.querySelectorAll<HTMLButtonElement>(".select-option"));

  function setOpen(open: boolean): void {
    menu.hidden = !open;
    button.setAttribute("aria-expanded", open ? "true" : "false");
    select.classList.toggle("open", open);
  }

  function setVersion(value: string, label: string, meta: string): void {
    input.value = value;
    labelEl.textContent = label || value;
    metaEl.textContent = meta || "Detect";
    options.forEach((opt) => {
      const selected = opt.dataset.value === value;
      opt.classList.toggle("active", selected);
      opt.setAttribute("aria-selected", selected ? "true" : "false");
    });
    // 通知外部（如 form.ts 配置保存）
    input.dispatchEvent(new Event("change", { bubbles: true }));
  }

  // 监听 input 变化以同步 UI（如 form.ts 加载持久化配置时）
  input.addEventListener("change", () => {
    const value = input.value;
    const matched = options.find((o) => o.dataset.value === value);
    if (matched) {
      labelEl.textContent = matched.dataset.label || value;
      metaEl.textContent = matched.dataset.meta || "Detect";
    }
    options.forEach((opt) => {
      const selected = opt.dataset.value === value;
      opt.classList.toggle("active", selected);
      opt.setAttribute("aria-selected", selected ? "true" : "false");
    });
  });

  function focusActive(): void {
    const active = options.find((o) => o.classList.contains("active")) || options[0];
    active?.focus();
  }

  button.addEventListener("click", () => setOpen(menu.hidden));

  button.addEventListener("keydown", (event) => {
    if (event.key === "ArrowDown" || event.key === "Enter" || event.key === " ") {
      event.preventDefault();
      setOpen(true);
      focusActive();
    }
  });

  options.forEach((option, index) => {
    option.addEventListener("click", () => {
      setVersion(option.dataset.value || "", option.dataset.label || "", option.dataset.meta || "");
      setOpen(false);
      button.focus();
    });

    option.addEventListener("keydown", (event) => {
      if (event.key === "ArrowDown" || event.key === "ArrowUp") {
        event.preventDefault();
        const offset = event.key === "ArrowDown" ? 1 : -1;
        const next = (index + offset + options.length) % options.length;
        options[next].focus();
      } else if (event.key === "Home" || event.key === "End") {
        event.preventDefault();
        options[event.key === "Home" ? 0 : options.length - 1].focus();
      } else if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        setVersion(option.dataset.value || "", option.dataset.label || "", option.dataset.meta || "");
        setOpen(false);
        button.focus();
      } else if (event.key === "Escape") {
        setOpen(false);
        button.focus();
      }
    });
  });

  document.addEventListener("click", (event) => {
    if (!select.contains(event.target as Node)) setOpen(false);
  });

  document.addEventListener("keydown", (event) => {
    if (event.key === "Escape") setOpen(false);
  });

  return { getValue: () => input.value };
}
