// 统一 API 请求封装
// 自动解析 HTTP 错误，失败时 toast 提示；支持 JSON / 文本 / 文件下载

import { toastError } from "./toast";

/** 从响应文本中提取可读错误信息 */
export function parseErrorText(text: string, fallback: string): string {
  if (!text) return fallback;
  try {
    const data = JSON.parse(text);
    if (typeof data.detail === "string") return data.detail;
    if (Array.isArray(data.detail)) {
      return data.detail.map((item: { msg?: string } | string) => typeof item === "string" ? item : (item.msg || JSON.stringify(item))).join("\n");
    }
    return JSON.stringify(data);
  } catch {
    return text;
  }
}

export class ApiError extends Error {
  status: number;
  constructor(status: number, message: string) {
    super(message);
    this.name = "ApiError";
    this.status = status;
  }
}

interface RequestOptions {
  /** 是否在失败时自动 toast 错误，默认 true */
  toastOnError?: boolean;
  /** 自定义错误前缀 */
  errorPrefix?: string;
}

/** 发起 fetch 并处理错误，返回 JSON */
export async function apiRequest<T = unknown>(url: string, init?: RequestInit, options: RequestOptions = {}): Promise<T> {
  const { toastOnError = true, errorPrefix } = options;
  let response: Response;
  try {
    response = await fetch(url, init);
  } catch (err) {
    const msg = `网络请求失败：${err instanceof Error ? err.message : String(err)}`;
    if (toastOnError) toastError(msg);
    throw new ApiError(0, msg);
  }

  if (!response.ok) {
    const text = await response.text().catch(() => "");
    const msg = parseErrorText(text, errorPrefix || `HTTP ${response.status}`);
    if (toastOnError) toastError(msg);
    throw new ApiError(response.status, msg);
  }

  return response.json() as Promise<T>;
}

/** 发起 fetch 返回纯文本 */
export async function apiText(url: string, init?: RequestInit, options: RequestOptions = {}): Promise<string> {
  const { toastOnError = true, errorPrefix } = options;
  let response: Response;
  try {
    response = await fetch(url, init);
  } catch (err) {
    const msg = `网络请求失败：${err instanceof Error ? err.message : String(err)}`;
    if (toastOnError) toastError(msg);
    throw new ApiError(0, msg);
  }

  if (!response.ok) {
    const text = await response.text().catch(() => "");
    const msg = parseErrorText(text, errorPrefix || `HTTP ${response.status}`);
    if (toastOnError) toastError(msg);
    throw new ApiError(response.status, msg);
  }

  return response.text();
}

// ---- 类型化 API 方法 ----

import type { Job, JobSummary } from "../types";

export interface CreateJobResponse {
  job_id: string;
  status: string;
  job: string;
}

export interface JobsListResponse {
  jobs: JobSummary[];
}

export const api = {
  health: () => apiRequest<{ status: string }>("/api/health", {}, { toastOnError: false }),

  createJob: (body: FormData) => apiRequest<CreateJobResponse>("/api/jobs", { method: "POST", body }),

  listJobs: () => apiRequest<JobsListResponse>("/api/jobs"),

  getJob: (id: string) => apiRequest<Job>(`/api/jobs/${id}`),

  getJobLog: (id: string) => apiText(`/api/jobs/${id}/log`, {}, { toastOnError: false }),

  deleteJob: (id: string) => apiRequest<{ deleted: boolean; job_id: string }>(`/api/jobs/${id}`, { method: "DELETE" }),

  cancelJob: (id: string) => apiRequest<{ cancelled: boolean; job_id: string }>(`/api/jobs/${id}/cancel`, { method: "POST" }),
};
