// 按钮 loading 组件
// 为按钮添加 spinner + 文字，自动管理 disabled 状态

export interface ButtonLoading {
  /** 开始 loading，保存原始文字并禁用 */
  start(loadingText?: string): void;
  /** 结束 loading，恢复原始文字并启用 */
  stop(): void;
  /** 按钮 disabled 时显示的 tooltip */
  setTooltip(text: string): void;
}

export function bindButton(button: HTMLButtonElement | HTMLAnchorElement): ButtonLoading {
  const original = button.textContent || "";

  const ensureSpinner = (): HTMLElement => {
    let spinner = button.querySelector(".btn-spinner") as HTMLElement | null;
    if (!spinner) {
      spinner = document.createElement("span");
      spinner.className = "btn-spinner";
      spinner.setAttribute("aria-hidden", "true");
      button.prepend(spinner);
    }
    return spinner;
  };

  return {
    start(loadingText = "处理中") {
      button.setAttribute("data-loading", "true");
      if ("disabled" in button) (button as HTMLButtonElement).disabled = true;
      else button.setAttribute("aria-disabled", "true");
      button.classList.add("is-loading");
      ensureSpinner();
      // 保留按钮文字，替换为 loading 文字
      // 移除除 spinner 外的所有文本节点
      Array.from(button.childNodes).forEach((node) => {
        if (node.nodeType === Node.TEXT_NODE) node.remove();
      });
      const label = document.createElement("span");
      label.className = "btn-loading-text";
      label.textContent = loadingText;
      button.appendChild(label);
    },
    stop() {
      button.removeAttribute("data-loading");
      if ("disabled" in button) (button as HTMLButtonElement).disabled = false;
      else button.removeAttribute("aria-disabled");
      button.classList.remove("is-loading");
      const spinner = button.querySelector(".btn-spinner");
      if (spinner) spinner.remove();
      const label = button.querySelector(".btn-loading-text");
      if (label) label.remove();
      // 恢复原始文字
      button.textContent = original;
    },
    setTooltip(text) {
      if (text) button.setAttribute("title", text);
      else button.removeAttribute("title");
    },
  };
}

/** 临时禁用按钮并显示原因 tooltip，返回恢复函数 */
export function disableWithReason(button: HTMLElement, reason: string): () => void {
  const btn = button as HTMLButtonElement;
  const wasDisabled = btn.disabled;
  const prevTitle = btn.getAttribute("title");
  btn.disabled = true;
  btn.setAttribute("title", reason);
  return () => {
    btn.disabled = wasDisabled;
    if (prevTitle === null) btn.removeAttribute("title");
    else btn.setAttribute("title", prevTitle);
  };
}
